import json
import re
from collections import defaultdict, Counter
import math

# Load clinical breast cancer data
clinical_file = var_functions.query_db:46
with open(clinical_file, 'r') as f:
    clinical_data = json.load(f)

# Load CDH1 mutation data
mutation_file = var_functions.query_db:44
with open(mutation_file, 'r') as f:
    mutation_data = json.load(f)

# Extract female patients with barcodes and histological types
female_patients = []
hist_type_map = {}

for record in clinical_data:
    desc = record.get('Patient_description', '')
    if 'FEMALE' in desc:
        # Extract patient barcode
        match = re.search(r'(TCGA-[A-Z0-9]+-[A-Z0-9]+)', desc)
        if match:
            barcode = match.group(1)
            hist_type = record.get('histological_type', '')
            if hist_type and hist_type.strip():
                female_patients.append(barcode)
                hist_type_map[barcode] = hist_type.strip()

print(f'Found {len(female_patients)} female BRCA patients with known histological types')

# Get CDH1 mutation status for female patients only
mutation_barcodes = set([entry['ParticipantBarcode'] for entry in mutation_data])
female_mutation_barcodes = mutation_barcodes.intersection(set(female_patients))

print(f'Found {len(female_mutation_barcodes)} female patients with CDH1 mutations')

# Build contingency table: Histological Type vs CDH1 Mutation Status
contingency_table = {}

for barcode in female_patients:
    hist_type = hist_type_map[barcode]
    mutation_status = 'Mutated' if barcode in female_mutation_barcodes else 'Wild-Type'

    if hist_type not in contingency_table:
        contingency_table[hist_type] = {'Mutated': 0, 'Wild-Type': 0}

    contingency_table[hist_type][mutation_status] += 1

print(f'\nContingency table (before filtering):')
for hist_type in sorted(contingency_table.keys()):
    counts = contingency_table[hist_type]
    print(f'  {hist_type}: {counts}')

# Exclude categories with marginal totals <= 10
# Calculate marginal totals for each histological type
filtered_table = {}
for hist_type, counts in contingency_table.items():
    row_total = counts['Mutated'] + counts['Wild-Type']
    if row_total > 10:
        filtered_table[hist_type] = counts

print(f'\nFiltered contingency table (row totals > 10):')
for hist_type in sorted(filtered_table.keys()):
    counts = filtered_table[hist_type]
    total = counts['Mutated'] + counts['Wild-Type']
    print(f'  {hist_type}: {counts} (total={total})')

# Check column totals (overall mutation status)
col_marginals = {'Mutated': 0, 'Wild-Type': 0}
for hist_type, counts in filtered_table.items():
    col_marginals['Mutated'] += counts['Mutated']
    col_marginals['Wild-Type'] += counts['Wild-Type']

print(f'\nColumn marginals: {col_marginals}')
grand_total = col_marginals['Mutated'] + col_marginals['Wild-Type']
print(f'Grand total: {grand_total}')

# Check if any column has total <= 10
if col_marginals['Mutated'] <= 10 or col_marginals['Wild-Type'] <= 10:
    print('\nWARNING: One or more column totals <= 10. Analysis may be unreliable.')
    proceed = False
else:
    proceed = True

if not filtered_table:
    print('\nERROR: No histological types remain after filtering.')
    result = {'error': 'No categories with sufficient sample size (<= 10)'}
elif not proceed:
    result = {'error': 'Column marginals too small for reliable chi-square test'}
else:
    # Calculate chi-square statistic
    chi_square = 0
    expected_table = {}

    for hist_type, counts in filtered_table.items():
        expected_table[hist_type] = {}
        row_total = counts['Mutated'] + counts['Wild-Type']

        for mutation_status in ['Mutated', 'Wild-Type']:
            col_total = col_marginals[mutation_status]
            expected = (row_total * col_total) / grand_total
            expected_table[hist_type][mutation_status] = expected

            observed = counts[mutation_status]
            if expected > 0:
                chi_square += ((observed - expected) ** 2) / expected

    print(f'\nExpected frequencies:')
    for hist_type in sorted(expected_table.keys()):
        print(f'  {hist_type}: {expected_table[hist_type]}')

    print(f'\nChi-square statistic: {chi_square:.4f}')

    # Degrees of freedom: (rows - 1) * (columns - 1)
    df = (len(filtered_table) - 1) * (2 - 1)
    print(f'Degrees of freedom: {df}')

    result = {
        'chi_square': chi_square,
        'degrees_of_freedom': df,
        'contingency_table': filtered_table,
        'expected_frequencies': expected_table,
        'marginals': {
            'row_totals': {k: v['Mutated'] + v['Wild-Type'] for k, v in filtered_table.items()},
            'column_totals': col_marginals,
            'grand_total': grand_total
        }
    }

print('__RESULT__:')
print(json.dumps(result, indent=2))

